_shaderData.warp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

    // === QUANTUM CONSCIOUSNESS WARP SHADER ===
    // Multi-dimensional reality warping with musical intelligence

    vec2 uv_center = vUv - 0.5;
    float dist = length(uv_center);
    float angle = atan(uv_center.y, uv_center.x);

    // Sample current uFrame
    vec3 current = texture(sampler_main, vUv).xyz;
    ret = current;
    vec3 original = ret;

    // === ORGANIC CONSCIOUSNESS SPREADING ===
    // Neural growth pattern
    float spread_amount = length(uTexSize.zw) * 6;
    ret = max(ret, texture(sampler_main, (vUv - 0.5) * (1 - spread_amount) + 0.5).xyz * 0.95);
    ret = max(ret, texture(sampler_main, (vUv - 0.5) * (1 + spread_amount) + 0.5).xyz * 0.95);

    // === DIMENSIONAL FEEDBACK LOOPS ===
    // Create depth through blur differential
    vec3 blur_diff = ret - GetBlur1(vUv);
    ret += blur_diff * 0.25;

    // === VOLUMETRIC CONSCIOUSNESS NOISE ===
    // 3D noise injection for texture complexity
    float noise_scale = 0.08;
    float noise_speed = 0.15;
    vec4 consciousness_noise = texture3D(sampler_noisevol_hq,
        vec3(vUv * uTexSize.xy * texsize_noisevol_hq.zw * noise_scale,
               uTime * noise_speed + q1 * 0.3));

    // === QUANTUM COLOR SHIFTING ===
    // Musical intelligence drives channel manipulation
    float energy_threshold = q8;
    float consciousness_phase = q1;
    float dimensional_shift = q3;

    // Phase-based color rotation
    if (energy_threshold > 0.5) {
        float shift_factor = sin(consciousness_phase * 2 + dist * 5) * 0.5 + 0.5;
        if (shift_factor > 0.6) {
            ret.x = original.z * (1.0 - consciousness_noise.x * 0.3);
            ret.y = original.x * (1.0 - consciousness_noise.y * 0.3);
            ret.z = original.y * (1.0 - consciousness_noise.z * 0.3);
        }
    }

    // === CONDITIONAL NOISE INJECTION ===
    // Creates musical-reactive texture patterns
    float noise_threshold = 0.3 + energy_threshold * 0.2;
    if (ret.x > noise_threshold && ret.x < 0.8) {
        ret.y += consciousness_noise.x * 0.4 * energy_threshold;
    }
    if (ret.y > noise_threshold && ret.y < 0.8) {
        ret.z += consciousness_noise.y * 0.4 * energy_threshold;
    }
    if (ret.z > noise_threshold && ret.z < 0.8) {
        ret.x += consciousness_noise.z * 0.4 * energy_threshold;
    }

    // === DIMENSIONAL RIFT EFFECT ===
    // Strong dimensional shifts create reality tears
    if (dimensional_shift > 0.3) {
        float rift_pattern = sin(angle * 8 + uTime * 2) * sin(dist * 15 - uTime * 3);
        if (rift_pattern > 0.5) {
            ret = 1.0 - ret * 0.8;
        }
    }

    // === CONSCIOUSNESS DECAY ===
    // Intelligent temporal fade preserves intense moments
    float decay_rate = 0.018 - energy_threshold * 0.012;
    decay_rate = decay_rate - dimensional_shift * 0.01;
    ret -= max(0.005, decay_rate);

    // Ensure valid color range
    ret = clamp01(ret);

  fragColor = ret;
}

_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

    float neural_power = q8;
    float phase = q1;
    float chaos = q2;

    vUv = 0.5 + (vUv - 0.5) * 0.98;

    // Multi-resolution gradient analysis
    vec2 fine_d = uTexSize.zw * 4;
    vec2 med_d = uTexSize.zw * 8;
    vec2 coarse_d = uTexSize.zw * 16;

    vec3 fine_dx = GetPixel(vUv + vec2(1,0) * fine_d) - GetPixel(vUv - vec2(1,0) * fine_d);
    vec3 fine_dy = GetPixel(vUv + vec2(0,1) * fine_d) - GetPixel(vUv - vec2(0,1) * fine_d);
    vec3 med_dx = GetBlur1(vUv + vec2(1,0) * med_d) - GetBlur1(vUv - vec2(1,0) * med_d);
    vec3 med_dy = GetBlur1(vUv + vec2(0,1) * med_d) - GetBlur1(vUv - vec2(0,1) * med_d);
    vec3 coarse_dx = GetBlur2(vUv + vec2(1,0) * coarse_d) - GetBlur2(vUv - vec2(1,0) * coarse_d);
    vec3 coarse_dy = GetBlur2(vUv + vec2(0,1) * coarse_d) - GetBlur2(vUv - vec2(0,1) * coarse_d);

    // Gradient strength
    float gradient_strength = length(fine_dx) + length(med_dx) + length(coarse_dx);
    gradient_strength += length(fine_dy) + length(med_dy) + length(coarse_dy);

    // 3D noise with gradient coupling
    float tex_scale = 0.08 + chaos * 0.03;
    float time_scale = 0.25 + phase * 0.1;
    vec4 synaptic_noise = texture3D(sampler_noisevol_hq,
        vec3((vUv + vec2(lum(fine_dx), lum(fine_dy)) * 0.5) *
               uTexSize.xy * texsize_noisevol_hq.zw * tex_scale,
               uTime * time_scale + phase * 0.3));

    // Gradient-driven displacement
    vec2 field_force = vec2(lum(med_dx), lum(med_dy)) * 0.08;
    field_force += vec2(lum(coarse_dx), lum(coarse_dy)) * 0.05;
    vUv -= field_force * (0.6 + neural_power * 0.4);

    // Multi-layer composite
    vec3 layer_fine = GetPixel(vUv);
    vec3 layer_med = GetBlur1(vUv);
    vec3 layer_coarse = GetBlur2(vUv);

    // Differential amplification
    ret = abs(layer_fine * 2.0 + layer_med - layer_coarse * 0.6);

    // Musical noise coupling
    ret *= lum(synaptic_noise) * (2.0 + neural_power * 1.0);

    // Contrast sculpting
    ret = pow(ret, vec3(0.75, 0.70, 0.65));
    ret = ret * (1.0 + (0.5 - ret) * 0.2);

    // Neural inversion
    float invert_amount = 0.5 + neural_power * 0.2;
    ret = mix(ret, 1.0 - ret, invert_amount);

    // Chroma shifting
    ret.r *= 1.02;
    ret.g *= 0.98;
    ret.b *= 1.05;

    ret = clamp01(ret);

  fragColor = ret;
}
